    {
      "path": "README.md",
      "content": "# Project Management API
This is a Node.js monolithic application for managing projects, tasks, members, and comments. It uses in-memory repositories and follows a modular structure under `src/modules/`.

## Features
- In-memory data storage
- Modular architecture with separate modules for projects, tasks, members, and comments
- RESTful API endpoints for CRUD operations
- Error handling with consistent payload shape `{ error: { code, message } }`

## Getting Started
1. Clone the repository.
2. Install dependencies using `npm install`.
3. Run the application using `node src/server.js`.

## Endpoints
- **GET /health**: Check the health of the API.
- **POST /projects**: Create a new project.
- **GET /projects**: List all projects.
- **GET /projects/:projectId**: Get a specific project by ID.
- **POST /projects/:projectId/members**: Add a member to a project.
- **GET /projects/:projectId/members**: List all members of a project.
- **POST /projects/:projectId/tasks**: Create a new task for a project.
- **GET /projects/:projectId/tasks**: List all tasks of a project.
- **GET /projects/:projectId/tasks?status=done**: Filter tasks by status (e.g., done).
- **PATCH /projects/:projectId/tasks/:taskId**: Update the status of a task.
- **POST /projects/:projectId/tasks/:taskId/comments**: Add a comment to a task.
- **GET /projects/:projectId/tasks/:taskId/comments**: List all comments of a task."
    },
    {
      "path": "package.json",
      "content": "{
  "name": "project-management-api",
  "version": "1.0.0",
  "description": "A Node.js monolithic application for managing projects, tasks, members, and comments.",
  "main": "src/server.js",
  "scripts": {
    "start": "node src/server.js"
  },
  "dependencies": {
    "express": "^4.17.1"
  }
}"
    },
    {
      "path": "src/app.js",
      "content": "const express = require('express');
const projectsRouter = require('./modules/projects/routes');

const app = express();
app.use(express.json());

// Health check endpoint
app.get('/health', (req, res) => {
  res.json({ ok: true });
});

// Mount routers
app.use('/projects', projectsRouter);

module.exports = app;"
    },
    {
      "path": "src/server.js",
      "content": "const http = require('http');
const app = require('./app');

const PORT = process.env.PORT || 3000;

const server = http.createServer(app);
server.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});"
    },
    {
      "path": "src/modules/projects/routes.js",
      "content": "const express = require('express');
const projectsService = require('./service');

const router = express.Router();

// Create a new project
router.post('/', async (req, res) => {
  try {
    const project = await projectsService.createProject(req.body);
    res.status(201).json(project);
  } catch (error) {
    if (error.code === 'PROJECT_EXISTS') {
      return res.status(409).json({ error: { code: 'PROJECT_EXISTS', message: 'Project already exists' } });
    }
    res.status(500).json({ error: { code: 'INTERNAL_ERROR', message: 'Internal server error' } });
  }
});

// List all projects
router.get('/', async (req, res) => {
  try {
    const projects = await projectsService.getAllProjects();
    res.json(projects);
  } catch (error) {
    res.status(500).json({ error: { code: 'INTERNAL_ERROR', message: 'Internal server error' } });
  }
});

// Get a specific project by ID
router.get('/:projectId', async (req, res) => {
  try {
    const project = await projectsService.getProjectById(req.params.projectId);
    if (!project) {
      return res.status(404).json({ error: { code: 'PROJECT_NOT_FOUND', message: 'Project not found' } });
    }
    res.json(project);
  } catch (error) {
    res.status(500).json({ error: { code: 'INTERNAL_ERROR', message: 'Internal server error' } });
  }
});

module.exports = router;"
    },
    {
      "path": "src/modules/projects/service.js",
      "content": "const { randomUUID } = require('crypto');
const projectsRepository = require('../repository');

async function createProject(projectData) {
  const existingProject = await projectsRepository.getProjectByName(projectData.name);
  if (existingProject) {
    throw new Error('PROJECT_EXISTS');
  }
  const project = { id: randomUUID(), ...projectData };
  await projectsRepository.saveProject(project);
  return project;
}

async function getAllProjects() {
  return projectsRepository.getAllProjects();
}

async function getProjectById(projectId) {
  return projectsRepository.getProjectById(projectId);
}

module.exports = { createProject, getAllProjects, getProjectById };"
    },
    {
      "path": "src/modules/projects/repository.js",
      "content": "let projects = [];

function saveProject(project) {
  projects.push(project);
}

function getAllProjects() {
  return projects;
}

function getProjectById(projectId) {
  return projects.find(p => p.id === projectId);
}

function getProjectByName(name) {
  return projects.find(p => p.name === name);
}

module.exports = { saveProject, getAllProjects, getProjectById, getProjectByName };"
    },
    {
      "path": "src/lib/errors.js",
      "content": "class NotFoundError extends Error {
  constructor(message) {
    super(message);
    this.code = 'NOT_FOUND';
  }
}

module.exports = { NotFoundError };
"
    },
    {
      "path": "src/lib/id.js",
      "content": "const { randomUUID } = require('crypto');

function generateId() {
  return randomUUID();
}

module.exports = { generateId };
"
    }
